import{_ as e,c as t,o as r,ah as d}from"./chunks/framework.C-x9UAyH.js";const p=JSON.parse('{"title":"Máquinas Virtuales","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"aws/maquinas_virtuales.md","filePath":"aws/maquinas_virtuales.md","lastUpdated":1760459112000}'),s={name:"aws/maquinas_virtuales.md"};function i(n,a,o,l,u,c){return r(),t("div",null,[...a[0]||(a[0]=[d('<h1 id="maquinas-virtuales" tabindex="-1">Máquinas Virtuales <a class="header-anchor" href="#maquinas-virtuales" aria-label="Permalink to &quot;Máquinas Virtuales&quot;">​</a></h1><h2 id="amazon-ec2" tabindex="-1">Amazon EC2 <a class="header-anchor" href="#amazon-ec2" aria-label="Permalink to &quot;Amazon EC2&quot;">​</a></h2><p>Amazon Elastic Compute Cloud (EC2) es un servicio de cómputo en la nube ofrecido por Amazon Web Services (AWS) que revoluciona la forma en que las empresas gestionan y escalan sus recursos informáticos. EC2 permite a las organizaciones <strong>lanzar y administrar máquinas virtuales</strong> (instancias) en la nube de AWS de manera flexible y escalable.</p><table tabindex="0"><thead><tr><th>Funcionalidad</th><th>Descripción</th></tr></thead><tbody><tr><td>Crea entornos de desarrollo y pruebas</td><td>Las máquinas virtuales pueden usarse como entornos aislados de desarrollo y pruebas que incluyen todas las funciones, sin afectar el resto de la infraestructura.</td></tr><tr><td>Brinda asistencia a desarrolladores</td><td>Es posible activar, desactivar, migrar y adaptar las máquinas virtuales para lograr la máxima flexibilidad en el desarrollo.</td></tr><tr><td>Crea entornos híbridos</td><td>Las máquinas virtuales ofrecen bases para un entorno en la nube respaldado por uno on-premise, brindando flexibilidad sin abandonar los sistemas antiguos.</td></tr></tbody></table><h2 id="ec2-vs-vm-on-premises" tabindex="-1">EC2 vs VM (on-premises) <a class="header-anchor" href="#ec2-vs-vm-on-premises" aria-label="Permalink to &quot;EC2 vs VM (on-premises)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Aspecto</th><th>VMs On-Premises</th><th>Amazon EC2 (AWS)</th></tr></thead><tbody><tr><td>Ubicación</td><td>Infraestructura local, en servidores propios</td><td>Infraestructura en la nube de AWS</td></tr><tr><td>Control</td><td>Control total sobre hardware y red</td><td>Control parcial, gestionado por AWS</td></tr><tr><td>Escalabilidad</td><td>Limitada por el hardware disponible</td><td>Alta escalabilidad bajo demanda</td></tr><tr><td>Costos</td><td>Altos costos iniciales (hardware, mantenimiento, energía)</td><td>Pago por uso, sin necesidad de inversión inicial</td></tr><tr><td>Mantenimiento</td><td>A cargo del equipo de TI interno</td><td>AWS se encarga del mantenimiento y parches de seguridad</td></tr><tr><td>Tiempo de aprovisionamiento</td><td>Lento, requiere compra/configuración de hardware</td><td>Rápido, con instancias disponibles casi al instante</td></tr><tr><td>Seguridad</td><td>Totalmente administrada internamente</td><td>Compartida con AWS, con opciones avanzadas de seguridad</td></tr><tr><td>Casos ideales</td><td>Cuando se necesita control total y ya se dispone del hardware</td><td>Cuando se requiere agilidad, escalabilidad y flexibilidad</td></tr></tbody></table>',6)])])}const b=e(s,[["render",i]]);export{p as __pageData,b as default};
